import { useEffect, useMemo, useState } from "react";
import api from "../services/api";
import "./Dashboard.css";
import Navbar from "../components/Navbar";

// same image as login/signup
import bg from "../assets/Image.jpg";

function Dashboard() {
  const role = localStorage.getItem("role");

  const [items, setItems] = useState([]);
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState("");
  const [showCart, setShowCart] = useState(false);

  // background image style
  const pageStyle = {
    backgroundImage: `url(${bg})`,
    backgroundSize: "cover",
    backgroundPosition: "center",
    minHeight: "100vh"
  };

  useEffect(() => {
    fetchItems();
  }, []);

  const fetchItems = async () => {
    try {
      const res = await api.get("/items");
      setItems(res.data || []);
    } catch (err) {
      console.error(err);
    }
  };

  const getId = (item) => item.id ?? item.itemId;

  const addToCart = (item) => {
    const id = getId(item);

    setCart((prev) => {
      const existing = prev.find((i) => getId(i) === id);

      if (existing) {
        return prev.map((i) =>
          getId(i) === id ? { ...i, qty: i.qty + 1 } : i
        );
      }

      return [...prev, { ...item, id, qty: 1 }];
    });
  };

  const increase = (id) => {
    setCart((prev) =>
      prev.map((i) =>
        getId(i) === id ? { ...i, qty: i.qty + 1 } : i
      )
    );
  };

  const decrease = (id) => {
    setCart((prev) =>
      prev
        .map((i) =>
          getId(i) === id ? { ...i, qty: i.qty - 1 } : i
        )
        .filter((i) => i.qty > 0)
    );
  };

  const total = useMemo(() => {
    return cart.reduce(
      (sum, i) => sum + Number(i.price || 0) * i.qty,
      0
    );
  }, [cart]);

  const groupedItems = useMemo(() => {
    const filtered = items.filter((item) =>
      (item.name || "")
        .toLowerCase()
        .includes(search.toLowerCase())
    );

    return filtered.reduce((acc, item) => {
      const cat = item.category || "Other";
      if (!acc[cat]) acc[cat] = [];
      acc[cat].push(item);
      return acc;
    }, {});
  }, [items, search]);

  if (role === "ROLE_ADMIN") {
    return (
      <div style={pageStyle}>
        <Navbar />
        <h2>Admin Dashboard</h2>
      </div>
    );
  }

  return (
    <div style={pageStyle}>
      <Navbar />

      <div className="header">
        <h2>Grocery Store</h2>

        <input
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <button onClick={() => setShowCart(!showCart)}>
          Cart ({cart.reduce((s, i) => s + i.qty, 0)})
        </button>
      </div>

      <div className="main">

        <div className="products">
          {Object.keys(groupedItems).map((cat) => (
            <div key={cat}>
              <h3>{cat}</h3>

              <div className="grid">
                {groupedItems[cat].map((item) => (
                  <div className="card" key={getId(item)}>
                    <img src={item.imageUrl} alt={item.name} />
                    <h4>{item.name}</h4>
                    <p>₹ {item.price}</p>

                    <button onClick={() => addToCart(item)}>
                      Add to Cart
                    </button>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        {showCart && (
          <div className="cart">
            <h3>Cart</h3>

            {cart.map((item) => (
              <div key={getId(item)}>
                <p>{item.name}</p>

                <button onClick={() => decrease(getId(item))}>-</button>
                {item.qty}
                <button onClick={() => increase(getId(item))}>+</button>

                <span>₹{item.price * item.qty}</span>
              </div>
            ))}

            <h3>Total: ₹{total}</h3>

            <button
              onClick={() => {
                alert("Order placed 🎉");
                setCart([]);
                setShowCart(false);
              }}
            >
              Checkout
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default Dashboard;
